#include <bits/stdc++.h>
using namespace std;
bool srn(int a){
	if(a%4==0&&a%100!=0){
		return true;
	}else if(a%100==0&&a%400==0){
		return true;
	}else{
		return 0;
	}
}
unsigned long long n;
int main() {
	int x,y;
	cin>>x>>y;
	for(int i=x+1;i<y;i++){
		if(srn(i)){
			n+=i;
		}
	}
	cout<<n;
	return 0;
}
